export default function EvidenceScopeField(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><label className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">Evidence scope</label><div className="mt-2 rounded-2xl border border-[#ececee] bg-[#f4f5f6] px-4 py-3"><strong className="text-[#111]">{scopes[active][0]}</strong><span className="ml-2 text-xs text-[#4a4a4f]">{scopes[active][1]}</span></div><div role="radiogroup" aria-label="Evidence scope options" className="relative mt-3 grid grid-cols-3 gap-1">{scopes.map((scope,index)=><button key={scope[0]} type="button" role="radio" aria-checked={active===index} onClick={()=>setActive(index)} className="relative z-10 min-h-11 rounded-xl px-1 text-xs font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{scope[0]}</button>)}<motion.i aria-hidden className="absolute bottom-0 h-1 w-1/3 rounded-full bg-[#f2aa30]" animate={{x:`${active*100}%`}} transition={reduced?{duration:0}:{type:"spring",stiffness:340,damping:26}}/></div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{scopes[active][0]} evidence selected.</p></section>}
